import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"23. Alternative Dispute Resolution Procedure","description":"","frontmatter":{"title":"23. Alternative Dispute Resolution Procedure","eba":"Mental Health Services 2024-2028","topics":["wages","disputes","union-matters","classifications"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/consultation-disputes/23-alternative-dispute-resolution-procedure.md","filePath":"ebas/mental-health/common-terms/consultation-disputes/23-alternative-dispute-resolution-procedure.md"}'),a={name:"ebas/mental-health/common-terms/consultation-disputes/23-alternative-dispute-resolution-procedure.md"};function s(r,e,l,p,h,d){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_23-alternative-dispute-resolution-procedure" tabindex="-1">23. Alternative Dispute Resolution Procedure <a class="header-anchor" href="#_23-alternative-dispute-resolution-procedure" aria-label="Permalink to &quot;23. Alternative Dispute Resolution Procedure&quot;">​</a></h1><p><strong>23.1</strong> Application The Independent Disputes Resolution Industry Panel (Panel) is empowered to hear and determine dispute applications regarding the following matters:</p><p><strong>(a)</strong> A dispute under this Agreement in relation to the classification of an employee; and</p><p><strong>(b)</strong> Alleged underpayments, where the Employer and Employee agree to have the dispute about an alleged underpayment determined by the Panel.</p><p><strong>23.2</strong> Composition and principles of the Panel</p><p><strong>(a)</strong> The Panel will comprise three persons being:</p><p><strong>(i)</strong> A nominee of the Union (on behalf of Employees);</p><p><strong>(ii)</strong> A nominee of the VHIA (on behalf of Employers); and</p><p><strong>(iii)</strong> an independent chairperson (Chair) agreed by the Unions and the VHIA or, in the absence of agreement, as nominated by the Minister for Health. Note: The nominee of the Unions or VHIA will be for each matter before the Panel but may be renominated as required.</p><p><strong>(b)</strong> The Panel Chair shall act as an independent third party in deliberations of the Panel.</p><p><strong>(c)</strong> A nominee on the Panel does not receive any additional remuneration for their service and must not accept the nomination if it results in a conflict of interest.</p><p><strong>(d)</strong> The Panel will commence to determine an application made under this clause within 21 days of receiving the application and conclude its deliberations as expeditiously as possible.</p><p><strong>(e)</strong> The Panel shall act independently of the Unions and the VHIA.</p><p><strong>(f)</strong> The parties to an application to the Panel bear their own costs (save for the Chair).</p><p><strong>(g)</strong> The Panel shall be responsible for determining its own procedure, provided that it applies the rules of natural justice and procedural fairness and be consistent with the requirements of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22</a> Disputes Settling Procedure.</p><p><strong>(h)</strong> The Panel shall apply an inquisitorial procedure, rather than an adversarial one.</p><p><strong>(i)</strong> The Panel may decide to hear a matter in the workplace. In such cases the employer shall provide a suitable meeting room and other relevant facilities for any date requested by the Panel. The employer will allow the Panel to inspect any work site if the Panel believes this will assist it in determining a matter, subject to any health, safety and privacy considerations. A party to a dispute may request that the Panel hear a matter in a workplace. The Panel will consider such a request and determine for itself the best location for hearing a matter.</p><p><strong>(j)</strong> In the exercise of its functions, the Panel shall do such things as are necessary to ensure that:</p><p><strong>(i)</strong> matters are dealt with expeditiously; and</p><p><strong>(ii)</strong> where possible it does not deal with unnecessarily complex legal arguments in hearing/determining a matter.</p><p><strong>(k)</strong> Lawyers and paid agents, who are not direct employees of the Unions, VHIA, Department or an employer may not be given permission to appear before the Panel.</p><p><strong>(l)</strong> A party to a dispute that is being dealt with under this clause shall not make an application to the FWC for it to deal with the same dispute, other than an</p><p>application made under clause 23.5(k)-23.5(l). Nothing prevents an application to the FWC where the Panel ceases to deal with a dispute without having made a determination.</p><p><strong>23.3</strong> Functions of the Panel Chair</p><p><strong>(a)</strong> The Chair shall perform the following functions:</p><p><strong>(i)</strong> Chair proceedings of the Panel</p><p><strong>(ii)</strong> Conciliate matters, by chairing conferences between the employer(s) and/or their representative/s, and the Union; and</p><p><strong>(iii)</strong> Anything else necessary to give effect to the provisions of this clause.</p><p><strong>23.4</strong> Application to Panel to deal with a dispute</p><p><strong>(a)</strong> Either an Employer or an Employee (or their representatives) may make an application to the Panel regarding a dispute about matters listed at 22.1 only where the Parties have attempted to resolve the dispute at the workplace as described at <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22.4</a> of the enterprise agreement.</p><p><strong>(b)</strong> If the provisions of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22.4</a> (Discussion of dispute at workplace) or <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">Clause 22.2</a> (Obligations of this Agreement) have not been complied with prior to the application, the Chair will refer the parties back to the workplace to attempt resolution through discussion at the workplace level in the first instance.</p><p><strong>(c)</strong> For the purpose of this subclause, an attempt to resolve the dispute means the exchange and consideration of the documents referred to in sub-clause 23.4(f)(iii) to 23.4(f)(vii).</p><p><strong>(d)</strong> In the absence of a Position Description, the Employer and Employee will co- operate to ensure a position description is developed within 8 weeks of a request.</p><p><strong>(e)</strong> The Employer will provide a response to the document referred to 23.4(f)(vi) within 4 weeks of it being received.</p><p><strong>(f)</strong> To be considered, applications to the Panel under subclause 23.1(a) must include the following:</p><p><strong>(i)</strong> Name of Applicant and contact details</p><p><strong>(ii)</strong> Name of Employer representative and contact details</p><p><strong>(iii)</strong> Current Position Description</p><p><strong>(iv)</strong> Current classification under the Agreement</p><p><strong>(v)</strong> Proposed classification under the Agreement</p><p><strong>(vi)</strong> Proposed classification and rationale (having regard to the classification descriptors within the Agreement)</p><p><strong>(vii)</strong> The Employer&#39;s response to the proposed classification and rationale The application is to be forwarded to the Employer</p><p><strong>(g)</strong> Application by an Employee</p><p><strong>(i)</strong> Before referral to the Panel for determination, the Chair in the first instance shall review the employee’s application to determine that the nature of the dispute is within the scope of this clause and therefore able to be determined by the Panel.</p><p><strong>(ii)</strong> The Chair will notify the employee, The Unions, VHIA and the Employer of their findings with respect to scope.</p><p><strong>(iii)</strong> If the chair finds the employee’s application is not within the scope of this clause the Chair will notify the employee and that their application is not able to be heard by the Panel.</p><p><strong>(iv)</strong> If the Chair finds the employee’s application is within the scope of this clause the Chair will notify the employee that it will be dealt with under this clause.</p><p><strong>23.5</strong> Role, procedures and determinations of the Panel</p><p><strong>(a)</strong> In dealing with an application, the Panel will:</p><p><strong>(i)</strong> utilise available relevant material</p><p><strong>(ii)</strong> apply the provisions of the Agreement; and</p><p><strong>(iii)</strong> in the case of submissions under clause 23.5(f) below consider any materials submitted by or on behalf of the Department.</p><p><strong>(b)</strong> Subject to the provisions of this clause, proceedings of the Panel shall be conducted as informally as possible and undertaken with all possible expediency.</p><p><strong>(c)</strong> The Panel may inform itself in any manner it sees fit including, in the case of a classification application, by seeking the views of an expert advisor (who is not an employee of the health service subject of the application) agreed by the Panel to provide clinical expertise in an area of clinical practice relevant to the classification matter under consideration.</p><p><strong>(d)</strong> The Panel is not bound by the rules or practices as to evidence and may inform itself on any matter it thinks fit. In any event, an employee providing evidence to the Panel will not be subjected to any form of cross examination by any person without limiting the questions the Panel may ask.</p><p><strong>(e)</strong> The Employer or VHIA and the Employee/s and/or Unions can advocate to the Panel.</p><p><strong>(f)</strong> At the Panel’s discretion, the parties to a matter will present submissions verbally and/or in writing.</p><p><strong>(g)</strong> The parties to a dispute shall have full, unrestricted access to relevant information, except where the Panel determines that access to material is inappropriate for legal or confidentiality reasons.</p><p><strong>(h)</strong> An employee, including a Union representative, who is involved in a matter being heard by the Panel shall be allowed time off from their normal duties and paid their normal wages for time attending.</p><p><strong>(i)</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chair (including any dissenting decision or a summary of any dissenting decision) and provided to the parties.</p><p><strong>(j)</strong> No decision shall be regarded as a precedent.</p><p><strong>(k)</strong> A determination of the Panel will be considered binding unless either the Union or VHIA make an application to have the determination reviewed by the Commission within 14 days of receiving written determination.</p><p><strong>(l)</strong> An application to the Commission will include the application, determination, written reasons and supporting material.</p><p><strong>(m)</strong> Where applicable, the Commission will be assisted by the Chairperson, who will explain their recommendation, the application and supporting material, and inform the Commission of the position of the Union and the VHIA.</p><p><strong>(n)</strong> Where applicable, the Commission will adopt an inquisitorial procedure (rather than an adversarial procedure) and will in effect stand in the shoes of the Panel and determine whether the Panel decision under review was properly reached and may substitute or uphold the existing determination. Any determination under this clause will be final and binding upon the parties and will not be subject to an appeal of the Full Bench.</p><p><strong>23.6</strong> Additional Role of the Chair in considering matters affecting an Employer’s funding</p><p><strong>(a)</strong> The unions and the VHIA recognise that the Victorian Government, represented by the Department of Health, has a right to have its funding interests heard and considered in decisions of the Panel.</p><p><strong>(b)</strong> The interests of the Victorian Government represented by the Department include significant funding, policy and service delivery considerations and implications.</p><p><strong>23.7</strong> Materials to be provided to the Panel</p><p><strong>(a)</strong> A Party shall provide all relevant material to the Panel and the other Party as soon as practicable. Relevant material may include the following:</p><p><strong>(i)</strong> Staffing/EFT levels and profiles</p><p><strong>(ii)</strong> position descriptions</p><p><strong>(iii)</strong> rosters</p><p><strong>(iv)</strong> proposed and/or actual professional reporting lines for/to the proposed position/s</p><p><strong>(v)</strong> records relating to an application (for example: leave backfill, vacancies, absenteeism and leave accruals)</p><p><strong>(vi)</strong> organisational structure</p><p><strong>23.8</strong> Notification of Panel determinations</p><p><strong>(a)</strong> The Chair will notify the Unions, Employer and Employee, where applicable, of the Panel’s determination with respect to an application in writing within 14 days of the decision.</p><p><strong>(b)</strong> In the case of an application for a reclassification the determined grade will apply from the date of the application.</p><p><strong>(c)</strong> Until the determination of the Panel, the existing grade (where relevant) will continue to apply.</p><p><strong>(d)</strong> In the case of an application for a reclassification, where the Panel or, on review, the Commission determines that a lower classification applies, the Employee will have their current salary maintained.</p><p><strong>23.9</strong> Employee Release from normal duty</p><p><strong>(a)</strong> An Employee who is involved in a dispute before the Panel, including a Union nominee, will be released by the Employer with pay from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>(b)</strong> For the purposes of this clause ‘pay’ shall include shift allowances and any other payment the employee or Union nominee would have received had they not been released from duty as described above.</p><p><strong>23.10</strong> Withdrawal of application</p><p><strong>(a)</strong> The notifier of a dispute to the Panel may withdraw their application at any time.</p><p><strong>(b)</strong> Any notice of withdrawal of a matter shall be in writing.</p>',87)])])}const m=t(a,[["render",s]]);export{g as __pageData,m as default};
